{
  "$schema": "https://design-tokens.org/schema.json",
  "color": {
    "blue": {
      "500": {
        "$type": "color",
        "$value": "#3B82F6",
        "$description": "Primary brand blue, WCAG AA on white"
      }
    },
    "action": {
      "primary": {
        "$type": "color",
        "$value": "{color.blue.500}",
        "$description": "Default CTA button background"
      }
    }
  }
}
